import { z } from 'zod';

export const E2E331ClientActionSchema = z.object({
  scenarioId: z.literal('e2e-331'),
  fixture: z.enum(['paid_checkout_completed', 'checkout_cancelled', 'stale_webhook_replay', 'permission_denied']),
  action: z.enum(['start_checkout', 'receive_webhook', 'recover_state', 'retry_safe_refresh']),
  idempotencyKey: z.string().uuid(),
}).strict();

export const E2E331TrustedContextSchema = z.object({
  actorId: z.string().min(1),
  tenantId: z.string().min(1),
  role: z.enum(['owner','admin','member','viewer','system']),
  sessionId: z.string().min(1),
}).strict();

export const E2E331ResultSchema = z.object({
  status: z.enum(['passed','failed','denied','retryable_error']),
  httpStatus: z.union([z.literal(200), z.literal(202), z.literal(400), z.literal(403), z.literal(409), z.literal(422), z.literal(500)]),
  code: z.enum(['CHECKOUT_COMPLETED', 'CHECKOUT_CANCELLED', 'SIGNATURE_INVALID', 'REPLAY_SUPPRESSED', 'PERMISSION_DENIED']),
  userMessage: z.string().min(1),
  assertion: z.object({
    visibleState: z.literal('billing_state_recovered'),
    scenarioTitle: z.literal('Tax exempt customers with VAT ID'),
    redactedTelemetry: z.object({ event: z.literal('e2e.e2e-331.checked'), category: z.literal('saas_billing'), redacted: z.literal(true) }),
  }),
}).strict();

export const E2E331ProviderEventSchema = z.object({
  providerEventId: z.string().min(1),
  rawBodySha256: z.string().length(64),
  signatureHeader: z.string().min(10),
  secretVersion: z.enum(['active','previous']),
  paymentIntentId: z.string().min(1).optional(),
  invoiceId: z.string().min(1).optional(),
  retryable: z.boolean(),
  metadata: z.record(z.string()).transform((m) => ({ tenantHash: m.tenantHash, requestId: m.requestId })),
}).strict();

backend_solution:
// e2e-331: real provider boundary for Tax exempt customers with VAT ID
export async function handleE2E331Webhook(req, deps) {
  const raw = Buffer.from(await req.arrayBuffer());
  const verified = deps.provider.verifySignature(raw, req.headers);
  const inserted = await deps.inbox.insertOnce({ providerEventId: verified.id, type: verified.type, raw });
  if (!inserted) return { status: 200, body: { duplicate: true } };
  await deps.queue.enqueue('tax_exempt_customers_with_vat_id', { providerEventId: verified.id });
  return { status: 200, body: { received: true } };
}

